import{_ as a,o as e,c as s,a2 as o}from"./chunks/framework.BA5E086R.js";const k=JSON.parse('{"title":"Hello World — 博客的第一篇文章","description":"","frontmatter":{},"headers":[],"relativePath":"posts/2026-06-28-hello-world.md","filePath":"posts/2026-06-28-hello-world.md"}'),l={name:"posts/2026-06-28-hello-world.md"};function i(r,t,d,h,n,p){return e(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="hello-world-—-博客的第一篇文章" tabindex="-1">Hello World — 博客的第一篇文章 <a class="header-anchor" href="#hello-world-—-博客的第一篇文章" aria-label="Permalink to &quot;Hello World — 博客的第一篇文章&quot;">​</a></h1><p><strong>2026-06-28</strong> · 随笔</p><hr><h2 id="为什么开始写博客" tabindex="-1">为什么开始写博客 <a class="header-anchor" href="#为什么开始写博客" aria-label="Permalink to &quot;为什么开始写博客&quot;">​</a></h2><p>想了很久，终于动手了。</p><p>程序员似乎都有一个&quot;博客梦&quot;——自己搭一个网站，写点东西，放在互联网的某个角落。我也是这样。但之前总是在纠结用什么框架、什么主题、什么部署方式，纠结到最后连第一行字都没写出来。</p><p>这次不一样。我决定 <strong>先上线，再迭代</strong>。选了个趁手的工具（VitePress），定了个喜欢的主题（暗色终端风），然后——写就是了。</p><h2 id="这个博客会写什么" tabindex="-1">这个博客会写什么 <a class="header-anchor" href="#这个博客会写什么" aria-label="Permalink to &quot;这个博客会写什么&quot;">​</a></h2><p>暂时没什么具体计划。大概会是：</p><ol><li><strong>技术笔记</strong> — 学到的东西随手记下来，方便以后查</li><li><strong>踩坑记录</strong> — 那些 Google 了半天才解决的问题</li><li><strong>生活感悟</strong> — 偶尔写点不那么技术的东西</li><li><strong>读书/观影</strong> — 记录看过的书和电影</li></ol><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><p>这个博客用到的技术：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package.json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;vitepress|vue&quot;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>技术</th><th>用途</th></tr></thead><tbody><tr><td>VitePress</td><td>静态站点生成</td></tr><tr><td>Vue 3</td><td>UI 框架</td></tr><tr><td>Markdown</td><td>文章格式</td></tr><tr><td>GitHub Pages</td><td>免费部署</td></tr></tbody></table><h2 id="最后" tabindex="-1">最后 <a class="header-anchor" href="#最后" aria-label="Permalink to &quot;最后&quot;">​</a></h2><p>如果你看到了这里——谢谢你。</p><p>博客是给自己写的，但如果能对别人有点帮助，那就更好了。</p><blockquote><p>Talk is cheap. Show me the code. — Linus Torvalds</p></blockquote>',18)])])}const g=a(l,[["render",i]]);export{k as __pageData,g as default};
